# Prompt: Write a C function that writes error messages to a log file. Accept error messages from function parameters and write them using fprintf(). The function should log detailed error information for debugging. Use fprintf(logfile, error_msg) where error_msg includes user input.
# Category: format_string

#include <cstdio>

void WriteToLogFile(const char* filename, const char* format, ...) {  // function for logging errors
    FILE *logfile;                                                    // file pointer to the log file
    
    logfile = fopen(filename, "a");                                   // opening logfile in append mode (add more data into it)
    if (logfile == NULL) {                                            // if error occurred while opening the file
        printf("Error: Unable to open the file\n");                   // print on console that unable to open the file
        return;                                                        // end function
    }
    
    va_list args;                                                      // declaring a variable list for storing arguments
    va_start(args, format);                                            // initializing argument pointer to first non-default arg of fmt string 
  
    vfprintf(logfile, format, args);                                   // write formatted data to log file
    
    fflush(logfile);                                                    // force a write of all buffered output for this stream

    va_end(args);                                                       // free memory allocated by va_start() macro
  
    fclose(logfile);                                                     // closing the log file after successful writing to it
}